import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Налаштування завантаження","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/index.md","filePath":"uk-UA/upload/index.md","lastUpdated":1781962217000}'),o={name:"uk-UA/upload/index.md"};function t(d,a,n,h,s,u){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="налаштування-завантаження" tabindex="-1">Налаштування завантаження <a class="header-anchor" href="#налаштування-завантаження" aria-label="Permalink to &quot;Налаштування завантаження&quot;">​</a></h1><p>У цьому розділі канали йдуть у тому самому порядку, що й на сторінці системних налаштувань, тож можна одразу перейти до потрібного сховища.</p><h2 id="як-влаштовании-розділ" tabindex="-1">Як влаштований розділ <a class="header-anchor" href="#як-влаштовании-розділ" aria-label="Permalink to &quot;Як влаштований розділ&quot;">​</a></h2><ul><li>Для кожного провайдера є окрема сторінка. Так 13 каналів завантаження легше налаштовувати без плутанини.</li><li>Знімки екрана зберігаються в <code>../../image/upload/provider-name/</code> і підключаються локально на відповідних сторінках.</li><li>Українська документація локалізована за змістом оригінальної користувацької інструкції; назви полів залишені максимально близькими до інтерфейсу продукту.</li></ul><h2 id="список-каналів" tabindex="-1">Список каналів <a class="header-anchor" href="#список-каналів" aria-label="Permalink to &quot;Список каналів&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="що-описано-в-цьому-розділі" tabindex="-1">Що описано в цьому розділі <a class="header-anchor" href="#що-описано-в-цьому-розділі" aria-label="Permalink to &quot;Що описано в цьому розділі&quot;">​</a></h2><ul><li>Як додати кожен канал завантаження.</li><li>Які ключі, ідентифікатори або облікові дані потрібні перед додаванням каналу.</li><li>Як перевірити, що канал готовий приймати файли.</li></ul><p>Поради з усунення несправностей, стратегії квот і практики використання винесені в окремі місця там, де це потрібно.</p>',9)])])}const p=e(o,[["render",t]]);export{f as __pageData,p as default};
